// /frontend/src/components/Community.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";

// ----- Local persistence (swap to API later) -----
const LS_KEY = "wx:community:v1";

function loadPosts() {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (raw) return JSON.parse(raw);
  } catch {}
  // seed with a couple demo posts
  const seed = [
    {
      id: crypto.randomUUID(),
      city: "Atlanta, GA",
      text: "Anyone in Midtown—still raining? Thinking about walking to Piedmont Park.",
      votes: 5,
      createdAt: Date.now() - 1000 * 60 * 25,
      answers: [
        {
          id: crypto.randomUUID(),
          text: "Light drizzle now, roads are wet. Umbrella recommended.",
          createdAt: Date.now() - 1000 * 60 * 15,
        },
      ],
    },
    {
      id: crypto.randomUUID(),
      city: "Athens, GA",
      text: "How humid is it right now? Planning an evening run.",
      votes: 2,
      createdAt: Date.now() - 1000 * 60 * 60,
      answers: [],
    },
  ];
  localStorage.setItem(LS_KEY, JSON.stringify(seed));
  return seed;
}

function savePosts(posts) {
  try {
    localStorage.setItem(LS_KEY, JSON.stringify(posts));
  } catch {}
}

// ----- Small helpers -----
const timeAgo = (ts) => {
  const s = Math.floor((Date.now() - ts) / 1000);
  if (s < 60) return `${s}s ago`;
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return `${d}d ago`;
};

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }

// ----- Component -----
export default function Community({ defaultCity = "Atlanta, GA" }) {
  const [posts, setPosts] = useState(loadPosts());
  const [city, setCity] = useState(defaultCity);
  const [text, setText] = useState("");
  const [filter, setFilter] = useState("nearby"); // nearby | trending | new
  const [answerDraft, setAnswerDraft] = useState({}); // {postId: text}

  const textRef = useRef(null);

  useEffect(() => savePosts(posts), [posts]);

  const filtered = useMemo(() => {
    let list = [...posts];
    if (filter === "nearby") {
      list = list.filter(p => p.city.toLowerCase().includes(city.toLowerCase()));
    }
    if (filter === "trending") {
      list.sort((a, b) => b.votes - a.votes || b.createdAt - a.createdAt);
    } else if (filter === "new") {
      list.sort((a, b) => b.createdAt - a.createdAt);
    } else {
      // nearby default -> still show newest first after city filter
      list.sort((a, b) => b.createdAt - a.createdAt);
    }
    return list;
  }, [posts, filter, city]);

  const submitPost = () => {
    const t = text.trim();
    if (!t) return;
    const post = {
      id: crypto.randomUUID(),
      city: city || "Unknown",
      text: t.slice(0, 300),
      votes: 0,
      createdAt: Date.now(),
      answers: [],
    };
    setPosts([post, ...posts]);
    setText("");
    textRef.current?.focus();
  };

  const vote = (id, delta) => {
    setPosts(ps => ps.map(p => p.id === id ? { ...p, votes: clamp(p.votes + delta, 0, 9999) } : p));
  };

  const addAnswer = (postId) => {
    const t = (answerDraft[postId] || "").trim();
    if (!t) return;
    setPosts(ps => ps.map(p => {
      if (p.id !== postId) return p;
      return {
        ...p,
        answers: [...p.answers, { id: crypto.randomUUID(), text: t.slice(0, 280), createdAt: Date.now() }]
      };
    }));
    setAnswerDraft(a => ({ ...a, [postId]: "" }));
  };

  const quickCities = ["Atlanta, GA", "Athens, GA", "Savannah, GA", "Augusta, GA", "Marietta, GA"];

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-4">
      {/* Header + city selector */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3 mb-3">
        <div className="text-sm opacity-80">Community</div>
        <div className="flex flex-wrap items-center gap-2">
          <input
            value={city}
            onChange={(e) => setCity(e.target.value)}
            className="bg-white/10 px-3 py-2 rounded-lg text-sm outline-none"
            placeholder="Filter by city…"
          />
          <select
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="bg-white/10 px-2 py-2 rounded-lg text-sm outline-none"
            style={{ backgroundColor: "#ffffff", color: "#000000" }}
            title="Sort / Filter"
          >
            <option value="nearby">Nearby</option>
            <option value="trending">Trending</option>
            <option value="new">New</option>
          </select>
        </div>
      </div>

      {/* Quick city chips */}
      <div className="flex flex-wrap gap-2 mb-3">
        {quickCities.map(c => (
          <button
            key={c}
            className={`px-3 py-1 rounded-full text-xs ${c === city ? "bg-white/25" : "bg-white/10 hover:bg-white/20"}`}
            onClick={() => setCity(c)}
          >
            {c}
          </button>
        ))}
      </div>

      {/* Composer */}
      <div className="rounded-xl bg-white/5 p-3 mb-4">
        <div className="text-xs opacity-70 mb-1">Ask locals what it’s like right now</div>
        <textarea
          ref={textRef}
          value={text}
          onChange={(e) => setText(e.target.value)}
          maxLength={300}
          className="w-full bg-transparent outline-none resize-none h-20 text-sm"
          placeholder={`e.g., "Is it still raining near ${city}?" or "How windy is it on campus?"`}
        />
        <div className="flex items-center justify-between">
          <div className="text-xs opacity-60">{text.length}/300</div>
          <button
            onClick={submitPost}
            disabled={!text.trim()}
            className="px-3 py-1.5 rounded-lg bg-white/15 ring-1 ring-white/10 disabled:opacity-50 text-sm"
          >
            Post
          </button>
        </div>
      </div>

      {/* Posts */}
      <ul className="space-y-3">
        {filtered.map(p => (
          <li key={p.id} className="rounded-xl bg-white/5 p-3">
            <div className="flex items-start justify-between gap-3">
              <div className="flex-1 min-w-0">
                <div className="text-xs opacity-70 mb-1">{p.city} • {timeAgo(p.createdAt)}</div>
                <div className="text-sm leading-relaxed">{p.text}</div>
              </div>
              <div className="flex flex-col items-center gap-1 shrink-0">
                <button
                  className="px-2 py-1 rounded bg-white/10 hover:bg-white/20"
                  onClick={() => vote(p.id, +1)}
                  title="Upvote"
                >▲</button>
                <div className="text-xs opacity-80">{p.votes}</div>
                <button
                  className="px-2 py-1 rounded bg-white/10 hover:bg-white/20"
                  onClick={() => vote(p.id, -1)}
                  title="Downvote"
                >▼</button>
              </div>
            </div>

            {/* Answers */}
            {p.answers?.length ? (
              <div className="mt-3 space-y-2">
                {p.answers.map(a => (
                  <div key={a.id} className="rounded-lg bg-white/5 px-3 py-2">
                    <div className="text-xs opacity-60 mb-1">{timeAgo(a.createdAt)}</div>
                    <div className="text-sm">{a.text}</div>
                  </div>
                ))}
              </div>
            ) : null}

            {/* Answer box */}
            <div className="mt-3 flex gap-2">
              <input
                value={answerDraft[p.id] ?? ""}
                onChange={(e) => setAnswerDraft(d => ({ ...d, [p.id]: e.target.value }))}
                placeholder="Share what you see outside…"
                className="flex-1 bg-white/10 rounded-lg px-3 py-2 text-sm outline-none"
                maxLength={280}
              />
              <button
                onClick={() => addAnswer(p.id)}
                disabled={!((answerDraft[p.id] ?? "").trim())}
                className="px-3 py-2 rounded-lg bg-white/15 ring-1 ring-white/10 disabled:opacity-50 text-sm"
              >
                Reply
              </button>
            </div>
          </li>
        ))}
      </ul>

      {/* Empty state */}
      {!filtered.length && (
        <div className="text-sm opacity-70 text-center py-10">
          No posts yet for <span className="opacity-90">{city}</span>. Be the first!
        </div>
      )}
    </div>
  );
}
